  const countLiveNeighbors = ([x, y]: LiveCell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(cellKey(x + dx, y + dy))).length;

  const survives = (cell: LiveCell): boolean => {
    const count = countLiveNeighbors(cell);
    return count === 2 || count === 3;
  };

  return liveCells.filter(survives);
}
